input.content:
:root {
  --bg-deep: #07080b;
  --bg-mid: #12141b;
  --bg-light: #1e2230;

  --text-primary: #f6f7f8;
  --text-secondary: rgba(246, 247, 248, 0.62);

  --glass-bg: rgba(255, 255, 255, 0.015);
  --glass-border: rgba(255, 255, 255, 0.08);
  --glass-highlight: rgba(255, 255, 255, 0.14);

  --metal-light: #f5f5f6;
  --metal-mid: #d5d7db;
  --metal-dark: #9ea2a8;

  --accent: #89a7ff;
  --accent-strong: #5f86ff;

  --shadow-ambient: 0 34px 90px rgba(0, 0, 0, 0.62);
  --shadow-contact: 0 10px 24px rgba(0, 0, 0, 0.42);

  --radius-panel: 48px;
  --radius-card: 20px;
  --radius-pill: 999px;
  --font-sans: var(--font-inter), Inter, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

.page {
  min-height: 100vh;
  min-height: 100svh;
  min-height: 100dvh;
  overflow-x: hidden;
  display: flex;
  flex-direction: column;

  background-color: var(--bg-deep);
  background-image:
    radial-gradient(circle at 12% 12%, rgba(95, 134, 255, 0.16) 0%, transparent 48%),
    radial-gradient(circle at 88% 82%, rgba(20, 24, 40, 0.9) 0%, transparent 55%),
    linear-gradient(145deg, #07080b 0%, #040407 55%, #000 100%);
  color: var(--text-primary);
}

.nav {
  position: fixed;
  top: 22px;
  left: 50%;
  transform: translateX(-50%);

  display: flex;
  align-items: center;
  gap: 32px;
  padding: 12px 16px;

  background: rgba(5, 6, 10, 0.42);
  backdrop-filter: blur(30px) saturate(120%);
  -webkit-backdrop-filter: blur(28px) saturate(135%);

  border: 1px solid rgba(255, 255, 255, 0.08);
  border-top: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: var(--radius-pill);
  z-index: 100;
  box-shadow: 0 14px 54px rgba(0, 0, 0, 0.58);
}

.navLinks {
  display: flex;
  gap: 8px;
}

.navLink {
  appearance: none;
  border: 0;
  background: transparent;
  color: rgba(246, 247, 248, 0.58);
  text-decoration: none;
  font-size: 13px;
  font-weight: 430;
  padding: 10px 18px;
  border-radius: 999px;
  cursor: pointer;
  transition: color 0.2s ease, background 0.2s ease, box-shadow 0.2s ease;
}

.navLink:hover {
  color: rgba(246, 247, 248, 0.92);
}

.navLinkActive {
  color: rgba(246, 247, 248, 0.96);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.12) 0%, rgba(255, 255, 255, 0.04) 100%);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.12);
}

.main {
  flex: 1;
  min-height: 0;
  display: grid;
  grid-template-columns: 1fr 1.2fr;
  max-width: 1600px;
  margin: 0 auto;
  width: 100%;
  padding: 120px 80px 32px;
  gap: 80px;
  overflow: visible;
}

.textSection {
  display: flex;
  flex-direction: column;
  justify-content: center;
  position: relative;
  z-index: 10;
}

.badge {
  display: inline-flex;
  align-items: center;
  padding: 6px 12px;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: var(--radius-pill);
  font-size: 11px;
  color: rgba(246, 247, 248, 0.62);
  margin-bottom: 24px;
  width: fit-content;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.h1 {
  font-size: 72px;
  line-height: 1.05;
  font-weight: 480;
  letter-spacing: -0.05em;
  margin-bottom: 22px;
  color: var(--text-primary);

  font-style: italic;
  transform: skewX(-7deg);
  display: inline-block;

  background: linear-gradient(180deg, rgba(255, 255, 255, 1) 0%, rgba(180, 195, 255, 0.42) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;

  text-shadow:
    0 0 34px rgba(95, 134, 255, 0.12),
    0 14px 44px rgba(0, 0, 0, 0.55);
}

.subhead {
  font-size: 20px;
  line-height: 1.5;
  color: rgba(246, 247, 248, 0.72);
  font-weight: 320;
  max-width: 520px;
  margin-bottom: 48px;
  letter-spacing: -0.015em;
}

.ctaGroup {
  display: flex;
  align-items: center;
  gap: 18px;
}

.btnPrimary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 0 20px;
  height: 56px;
  border-radius: var(--radius-pill);

  background: linear-gradient(180deg, rgba(255, 255, 255, 0.16) 0%, rgba(255, 255, 255, 0.06) 100%);
  border: 1px solid rgba(255, 255, 255, 0.14);
  cursor: pointer;
  position: relative;
  text-decoration: none;
  appearance: none;

  box-shadow:
    0 18px 44px rgba(0, 0, 0, 0.55),
    inset 0 1px 0 rgba(255, 255, 255, 0.12);

  transition: transform 0.16s ease, box-shadow 0.2s ease, border-color 0.2s ease, background 0.2s ease;
}

.btnPrimary::before {
  content: '';
  position: absolute;
  inset: 1px;
  border-radius: var(--radius-pill);
  background: radial-gradient(circle at 30% 25%, rgba(255, 255, 255, 0.32) 0%, rgba(255, 255, 255, 0.12) 35%, rgba(255, 255, 255, 0.02) 70%, transparent 100%);
  pointer-events: none;
  opacity: 0.7;
}

.btnPrimary::after {
  content: '';
  position: absolute;
  inset: -10px;
  border-radius: var(--radius-pill);
  background: radial-gradient(circle, rgba(95, 134, 255, 0.18) 0%, transparent 60%);
  z-index: -1;
  pointer-events: none;
}

.btnPrimary svg {
  width: 22px;
  height: 22px;
  stroke: rgba(246, 247, 248, 0.92);
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
  fill: none;
  filter: drop-shadow(0 10px 20px rgba(0, 0, 0, 0.4));
}

.btnPrimary:hover {
  transform: translateY(-1px);
  border-color: rgba(255, 255, 255, 0.22);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.2) 0%, rgba(255, 255, 255, 0.07) 100%);
  box-shadow:
    0 22px 54px rgba(0, 0, 0, 0.6),
    inset 0 1px 0 rgba(255, 255, 255, 0.16);
}

.btnPrimary:active {
  transform: translateY(0px);
}

.btnLabel {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.01em;
  text-transform: none;
  color: rgba(246, 247, 248, 0.92);
  white-space: nowrap;
}

.canvasSection {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  perspective: 1200px;
  min-height: 680px;
}

.spatialBackdrop {
  position: absolute;
  inset: 40px -40px -40px 40px;
  background: linear-gradient(135deg, rgba(255, 255, 255, 0.018) 0%, rgba(0, 0, 0, 0.55) 100%);
  border-radius: var(--radius-panel);
  border-top: 1px solid rgba(255, 255, 255, 0.07);
  border-left: 1px solid rgba(255, 255, 255, 0.07);
  backdrop-filter: blur(44px);
  -webkit-backdrop-filter: blur(44px);
  box-shadow: -24px -24px 70px rgba(255, 255, 255, 0.012), 54px 54px 120px rgba(0, 0, 0, 0.72);
  transform: rotateY(-15deg) rotateX(5deg) translateZ(-100px);
  transform-style: preserve-3d;
  pointer-events: none;
}

.spatialScene {
  position: relative;
  width: 100%;
  height: 100%;
  transform-style: preserve-3d;
  transform: rotateY(-15deg) rotateX(5deg);
}

.splines {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: 1;
  transform: translateZ(0);
}

.splinePath {
  fill: none;
  stroke: rgba(255, 255, 255, 0.12);
  stroke-width: 1.5;
  stroke-dasharray: 6 6;
  animation: flow 20s linear infinite;
}

.splineGlow {
  fill: none;
  stroke: rgba(95, 134, 255, 0.065);
  stroke-width: 9;
  filter: blur(5px);
}

@keyframes flow {
  to {
    stroke-dashoffset: -100;
  }
}

.node {
  position: absolute;
  background: rgba(255, 255, 255, 0.018);
  backdrop-filter: blur(18px) saturate(160%);
  -webkit-backdrop-filter: blur(18px) saturate(160%);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-top: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: var(--radius-card);
  box-shadow: var(--shadow-ambient), inset 0 1px 0 rgba(255, 255, 255, 0.08);
  display: flex;
  flex-direction: column;
  z-index: 2;
  transition: transform 0.4s cubic-bezier(0.2, 0.8, 0.2, 1), border-color 0.2s ease;
}

.node:hover {
  transform: translateY(-8px) translateZ(40px);
  border-color: rgba(255, 255, 255, 0.22);
}

.cardVideo {
  width: 200px;
  height: 164px;
  padding: 12px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.cardVideoHeader {
  display: flex;
  align-items: center;
  gap: 8px;
}

.avatar {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.1);
}

.cardTitle {
  height: 4px;
  width: 60%;
  background: rgba(255, 255, 255, 0.22);
  border-radius: 2px;
}

.cardMeta {
  height: 4px;
  width: 40%;
  background: rgba(255, 255, 255, 0.12);
  border-radius: 2px;
  margin-top: 6px;
}

.nodeHeading {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: -0.01em;
  color: rgba(246, 247, 248, 0.92);
}

.nodeSubheading {
  margin-top: 6px;
  font-size: 11px;
  line-height: 1.35;
  color: rgba(246, 247, 248, 0.62);
}

.nodeKpiRow {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}

.nodeKpi {
  padding: 10px 10px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.018) 0%, rgba(0, 0, 0, 0.24) 100%);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.06);
}

.nodeKpiLabel {
  font-size: 10px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.52);
}

.nodeKpiValue {
  margin-top: 6px;
  font-size: 16px;
  font-weight: 650;
  letter-spacing: -0.02em;
  color: rgba(246, 247, 248, 0.95);
}

.playIndicator {
  align-self: flex-end;
  width: 24px;
  height: 24px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.1);
  display: flex;
  align-items: center;
  justify-content: center;
  backdrop-filter: blur(4px);
}

.playIndicator::after {
  content: '';
  width: 0;
  height: 0;
  border-style: solid;
  border-width: 4px 0 4px 6px;
  border-color: transparent transparent transparent rgba(255, 255, 255, 0.9);
  margin-left: 2px;
}

.node1 {
  top: 8%;
  left: 8%;
  transform: translateZ(20px);
  animation: float 6s ease-in-out infinite;
}

.node2 {
  top: 58%;
  left: 0;
  transform: translateZ(40px);
  animation: float 8s ease-in-out infinite 1s;
}

.node3 {
  top: 12%;
  right: 6%;
  transform: translateZ(30px);
  animation: float 7s ease-in-out infinite 2s;
}

.node4 {
  top: 62%;
  right: 2%;
  transform: translateZ(10px);
  animation: float 9s ease-in-out infinite 0.5s;
}

@keyframes float {
  0%,
  100% {
    transform: translateY(0) translateZ(var(--tz, 20px));
  }
  50% {
    transform: translateY(-12px) translateZ(var(--tz, 20px));
  }
}

.nodeInsight {
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) translateZ(80px);
  width: 140px;
  height: 140px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.028);
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow: 0 34px 88px rgba(0, 0, 0, 0.6), inset 0 2px 4px rgba(255, 255, 255, 0.12);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10;
  position: absolute;
}

.insightCore {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, var(--metal-light) 0%, var(--metal-mid) 60%, var(--metal-dark) 100%);
  box-shadow:
    -4px -4px 12px rgba(255, 255, 255, 0.04),
    10px 10px 28px rgba(0, 0, 0, 0.45),
    inset -2px -2px 6px rgba(0, 0, 0, 0.25),
    inset 2px 2px 6px rgba(255, 255, 255, 0.88);
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.insightCore::before {
  content: '';
  position: absolute;
  inset: -12px;
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.12);
  animation: pulse 4s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

@keyframes pulse {
  0% {
    transform: scale(1);
    opacity: 1;
  }
  100% {
    transform: scale(1.5);
    opacity: 0;
  }
}

.insightCore svg {
  width: 32px;
  height: 32px;
  stroke: #0b0b0c;
  stroke-width: 1.5;
  fill: none;
  filter: drop-shadow(0px 1px 0px rgba(255, 255, 255, 0.55));
}

.metaLabel {
  position: absolute;
  font-size: 10px;
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;
  color: rgba(255, 255, 255, 0.45);
  letter-spacing: 0.12em;
  pointer-events: none;
}

.lbl1 {
  bottom: -26px;
  left: 50%;
  transform: translateX(-50%);
}

.lbl2 {
  top: -24px;
  right: -20px;
}

.servicesSection {
  width: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
}

.servicesInner {
  max-width: 820px;
  margin: 0 auto;
  width: 100%;
}

.servicePanel {
  position: relative;
  width: 100%;
}

.serviceEyebrow {
  margin-bottom: 18px;
  font-size: 11px;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.46);
}

.serviceShell {
  position: relative;
  border-radius: 36px;
}

.serviceGlow {
  position: absolute;
  inset: -24px;
  border-radius: 44px;
  background:
    radial-gradient(circle at 20% 20%, rgba(255, 255, 255, 0.14) 0%, transparent 34%),
    radial-gradient(circle at 80% 30%, rgba(95, 134, 255, 0.28) 0%, transparent 38%),
    radial-gradient(circle at 50% 100%, rgba(166, 136, 255, 0.18) 0%, transparent 42%);
  filter: blur(26px);
  opacity: 0.95;
  pointer-events: none;
}

.serviceCard {
  position: relative;
  overflow: hidden;
  padding: 32px;
  border-radius: 36px;
  background:
    linear-gradient(145deg, rgba(255, 255, 255, 0.12) 0%, rgba(255, 255, 255, 0.04) 24%, rgba(11, 13, 20, 0.78) 100%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.04), rgba(255, 255, 255, 0.01));
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow:
    0 34px 100px rgba(0, 0, 0, 0.58),
    inset 0 1px 0 rgba(255, 255, 255, 0.18),
    inset 0 -1px 0 rgba(255, 255, 255, 0.04);
  backdrop-filter: blur(26px) saturate(140%);
  -webkit-backdrop-filter: blur(26px) saturate(140%);
}

.serviceCard::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(120deg, rgba(255, 255, 255, 0.14) 0%, transparent 26%, transparent 72%, rgba(255, 255, 255, 0.08) 100%);
  pointer-events: none;
}

.serviceHeader {
  position: relative;
  z-index: 1;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
}

.serviceKicker {
  margin: 0 0 10px;
  font-size: 12px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.52);
}

.serviceTitle {
  margin: 0;
  font-size: clamp(32px, 4vw, 48px);
  line-height: 1.02;
  letter-spacing: -0.05em;
  font-weight: 520;
  color: rgba(255, 255, 255, 0.96);
}

.serviceBadge {
  flex-shrink: 0;
  padding: 10px 14px;
  border-radius: 999px;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(255, 255, 255, 0.06);
  color: rgba(246, 247, 248, 0.8);
  font-size: 12px;
  letter-spacing: 0.04em;
}

.serviceDescription {
  position: relative;
  z-index: 1;
  margin: 24px 0 28px;
  max-width: 620px;
  font-size: 17px;
  line-height: 1.7;
  color: rgba(246, 247, 248, 0.72);
}

.serviceHighlights {
  position: relative;
  z-index: 1;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 14px;
}

.serviceHighlight {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 18px;
  border-radius: 22px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.08) 0%, rgba(255, 255, 255, 0.03) 100%);
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.08);
}

.highlightLabel {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.14em;
  color: rgba(246, 247, 248, 0.45);
}

.highlightValue {
  font-size: 15px;
  line-height: 1.45;
  color: rgba(246, 247, 248, 0.9);
}

.serviceFooter {
  position: relative;
  z-index: 1;
  margin-top: 28px;
}

.whatsappButton {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  min-height: 58px;
  padding: 0 22px;
  border-radius: 999px;
  text-decoration: none;
  color: rgba(255, 255, 255, 0.96);
  background: linear-gradient(135deg, #2ad36b 0%, #159947 100%);
  border: 1px solid rgba(255, 255, 255, 0.18);
  box-shadow:
    0 18px 40px rgba(21, 153, 71, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.22);
  transition: transform 0.16s ease, box-shadow 0.2s ease, filter 0.2s ease;
}

.whatsappButton:hover {
  transform: translateY(-1px);
  filter: brightness(1.03);
  box-shadow:
    0 22px 48px rgba(21, 153, 71, 0.38),
    inset 0 1px 0 rgba(255, 255, 255, 0.24);
}

.whatsappButton svg {
  width: 20px;
  height: 20px;
  stroke: currentColor;
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
  fill: none;
}

@media (max-width: 1024px) {
  .main {
    grid-template-columns: 1fr;
    padding: 100px 40px 32px;
    gap: 40px;
  }

  .textSection {
    justify-content: flex-start;
    align-items: center;
    text-align: center;
  }

  .subhead {
    margin-left: auto;
    margin-right: auto;
  }

  .ctaGroup {
    justify-content: center;
  }

  .canvasSection {
    min-height: 640px;
  }

  .spatialScene {
    transform: none;
  }

  .spatialBackdrop {
    transform: none;
  }

  .serviceHighlights {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 640px) {
  .nav {
    width: fit-content;
    max-width: calc(100% - 32px);
    left: 50%;
    right: auto;
    transform: translateX(-50%);
    justify-content: center;
  }

  .navLinks {
    gap: 8px;
  }

  .navLink {
    padding: 10px 14px;
  }

  .main {
    padding: 90px 20px 20px;
    gap: 24px;
  }

  .h1 {
    font-size: 56px;
  }

  .subhead {
    font-size: 18px;
    margin-bottom: 28px;
  }

  .canvasSection {
    align-items: stretch;
    min-height: 620px;
  }

  .spatialScene {
    width: min(100%, 320px);
    height: 640px;
    margin: 0 auto;
  }

  .spatialBackdrop {
    inset: 0;
    border-radius: 28px;
  }

  .serviceCard {
    padding: 24px;
    border-radius: 28px;
  }

  .serviceHeader {
    flex-direction: column;
  }

  .serviceTitle {
    font-size: 32px;
  }

  .serviceDescription {
    font-size: 16px;
  }

  .whatsappButton {
    width: 100%;
  }

  .cardVideo {
    width: min(320px, calc(100vw - 72px));
    height: auto;
  }

  .node {
    position: absolute;
    left: 50% !important;
    right: auto !important;
    transform: translateX(-50%) !important;
    animation: none;
  }

  .node1 { top: 20px; }
  .node3 { top: 180px; }
  .node2 { top: 340px; }
  .node4 { top: 500px; }
}
